CustomFunction.Calculation:
// Recursively builds the ORDER BY column list.
// Call with index = 0. orderBys is the raw JSON array from the query object.
// Example output: "CONTACT.lastName ASC, CONTACT.firstName ASC"
Let
(
[
_orderBy = JSONGetElement ( orderBys ; "[" & index & "]" ) ;
_column = JSONGetElement ( _orderBy ; "column" ) ;
_direction = JSONGetElement ( _orderBy ; "direction" ) ;
_clause = _column & " " & _direction ;
_rest = If ( index + 1 < orderByCount ; ", " & QueryBuildOrderBys_cf ( orderBys ; orderByCount ; index + 1 ) ; "" )
];
_clause & _rest
)
